+func resolveStaggerInterval(mode string, opts SpawnOptions, tracker *ratelimit.RateLimitTracker) time.Duration {
+	interval := opts.Stagger
+	switch mode {
+	case "fixed":
+		interval = opts.StaggerDelay
+	case "smart":
+		if tracker != nil {
+			interval = tracker.GetOptimalDelay("anthropic")
+		}
+	}
+	return interval
