+	fmt.Fprintf(w, "Total size:         %s\n", formatBytes(r.TotalSize))
+	fmt.Fprintf(w, "Compressed:         %d\n", r.CompressedCount)
+	if r.OldestTimeline != "" {
+		fmt.Fprintf(w, "Oldest:             %s\n", r.OldestTimeline)
