+		t.Fatalf("failed to marshal envelope: %v", err)
+	}
+
+	// Verify required fields are present
+	jsonStr := string(data)
+	requiredFields := []string{
+		"command", "subcommand", "session", "timestamp", "success",
+		"bead_id", "previous_pane", "previous_agent", "retry_count",
